    //Voor wanneer we beperkte persoonsgegevens nodig hebben
    @Override
    @InitializeAdmin
    public PersoonsDataManager createSimpel(Admin admin, Integer persoonId, RekenTijd rekenTijd, RegulManager regulManager) {
        PersoonsDataManagerImp dataManager = new PersoonsDataManagerImp();
        Set<Integer> teRekenenOpdrachtIds = findAllOpdrachtIds(admin, persoonId, rekenTijd);
        bepaalPersoonOpdrachtData(admin, persoonId, teRekenenOpdrachtIds, rekenTijd, dataManager, regulManager);
        return dataManager;
    }

    private Set<Integer> findAllOpdrachtIds(Admin admin, Integer persoonId, RekenTijd rekenTijd) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.findAllOpdrachtIds");
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setWerkTijdstip(rekenTijd.rekenTijdstip);
        temporalContext.setActualInterval(rekenTijd.rekenPeriode);

        CriteriaBuilder mcb = new CriteriaBuilder();
        mcb.and(PERSOON_ID, Criterium.EQ(persoonId));
        List<Object> opdrachtIds = dataService.findByCriteria(admin, OpdrachtPO.class, mcb, "id");

        temporalContext.clearActualInterval();
        temporalContext.clearWerkTijdstip();
        Set<Integer> opdrachtIdsSet = new HashSet<>();
        for (Object opdrachtId : opdrachtIds) {
            opdrachtIdsSet.add((Integer) opdrachtId);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return opdrachtIdsSet;
    }

    @Override
    @InitializeAdmin
    public PersoonsDataManager create(
            Admin admin, Integer persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, Integer fiscaalJaar,
            RegulManager regulManager, Rekenmodus rekenModus) {
        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        List<RekenHoofd> bestaanden = findBestaandeRekenResultaten(admin, persoonId, rekenTijd, loonCodeManager);
        Set<Integer> teRekenenOpdrachtIds = bepaalTeRekenenOpdrachten(admin, bestaanden, persoonId, opdrachtNrs, rekenTijd, rekenModus);
        bestaanden = bestaanden.stream()
                .filter(x -> teRekenenOpdrachtIds.contains(x.getOpdracht().getId()))
                .collect(Collectors.toList());
        return create(admin, persoonId, teRekenenOpdrachtIds, bestaanden, rekenTijd, fiscaalJaar, regulManager);
    }

    private PersoonsDataManager create(
            Admin admin, Integer persoonId, Set<Integer> teRekenenOpdrachtIds, List<RekenHoofd> bestaanden,
            RekenTijd rekenTijd, Integer fiscaalJaar, RegulManager regulManager) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.create");
        PersoonsDataManagerImp dataManager = new PersoonsDataManagerImp();

        bepaalPersoonOpdrachtData(admin, persoonId, teRekenenOpdrachtIds, rekenTijd, dataManager, regulManager);

        List<PersoonsInhouding> persoonsInhoudingen =
                persoonsInhoudingService.findByPersoon(admin, persoonId, rekenTijd.beslagDatum, rekenTijd.rekenTijdstip);
        dataManager.addPersoonsInhoudingenOpBeslagDatum(persoonsInhoudingen, rekenTijd.beslagDatum);

        PersoonsFiscaliteit beslagPersoonsFiscaliteit = persoonsFiscaliteitService.getByPersoonDatum(admin, persoonId, rekenTijd.beslagDatum);
        dataManager.addPersoonsFiscaliteitOpBeslagDatum(beslagPersoonsFiscaliteit, rekenTijd.beslagDatum);

        if (rekenTijd.isApo) {
            List<ApoHoofd> apoHoofden =
                    apoInputService.findByOpdrachtIdsBegindatum(admin, teRekenenOpdrachtIds, rekenTijd.beginDatum, rekenTijd.rekenTijdstip);
            dataManager.addApoInput(apoHoofden);
        }

        dataManager.addBestaandeRekenResultaten(bestaanden);
        dataManager.setDmfaAangifteAanwezig(isDmfaAangifteAanwezig(admin, rekenTijd));

        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        opvullenKwartaalResultaten(admin, rekenTijd, dataManager, loonCodeManager);
        bepaalVrijwilligeBrandweerData(admin, rekenTijd, dataManager, fiscaalJaar);
        bepaalSomWerkBonusFiscaalJaarData(admin, rekenTijd, dataManager, fiscaalJaar);
        bepaalOnthaaloudersWerkbonus(admin, persoonId, rekenTijd, dataManager);
        BepaalWerkbonusOverdrachtData bepaalWerkbonusOverdracht = new BepaalWerkbonusOverdrachtData(extraSqlService);
        bepaalWerkbonusOverdracht.bepaal(admin, persoonId, rekenTijd, dataManager);
        if (!rekenTijd.isApo) {
            bepaalPens2AntwerpenData(admin, rekenTijd, dataManager);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return dataManager;
    }

    private void bepaalSomWerkBonusFiscaalJaarData(Admin admin, RekenTijd rekenTijd, PersoonsDataManagerImp dataManager, Integer fiscaalJaar) {
        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.bepaalSomWerkBonusFiscaalJaarData");
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        if (RekenTools.heeftOpdrachtContractueel(persoon)) {
            Money verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikA =
                    werkBonusFiscaalJaarService.getVerminderingBvWerkbonusFiscaalJaarOtherMonths(admin, persoon, fiscaalJaar, rekenTijd.beginDatum,
                            WerkbonusLuik.LUIK_A);
            dataManager.setVerminderingBvWerkbonusFiscaalJaarOtherMonthsLuikA(verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikA);

            Money verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikB =
                    werkBonusFiscaalJaarService.getVerminderingBvWerkbonusFiscaalJaarOtherMonths(admin, persoon, fiscaalJaar, rekenTijd.beginDatum,
                            WerkbonusLuik.LUIK_B);
            dataManager.setVerminderingBvWerkbonusFiscaalJaarOtherMonthsLuikB(verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikB);

            Money werkbonusFiscaalJaarOtherMonthLuikA =
                    werkBonusFiscaalJaarService.getWerkbonusFiscaalJaarOtherMonths(admin, persoon, fiscaalJaar, rekenTijd.beginDatum, WerkbonusLuik.LUIK_A);
            dataManager.setWerkbonusFiscaalJaarOtherMonthsLuikA(werkbonusFiscaalJaarOtherMonthLuikA);

            Money werkbonusFiscaalJaarOtherMonthLuikB =
                    werkBonusFiscaalJaarService.getWerkbonusFiscaalJaarOtherMonths(admin, persoon, fiscaalJaar, rekenTijd.beginDatum, WerkbonusLuik.LUIK_B);
            dataManager.setWerkbonusFiscaalJaarOtherMonthsLuikB(werkbonusFiscaalJaarOtherMonthLuikB);
        }
        TimeLogContext.getInstance().endTimeLogging();
    }

    private boolean isDmfaAangifteAanwezig(Admin admin, RekenTijd rekenTijd) {
        ConstantManager constantManager = new ConstantManagerImp(admin, constantService);
        HeeftPatronaleVermindering707 heeftVermindering = new HeeftPatronaleVermindering707(constantManager, rekenTijd);

        if (heeftVermindering.getPeriodeActiefOptioneel().contains(rekenTijd.beginDatum)) {
            int jaar = rekenTijd.beginDatum.getYear();
            int kwartaal = TimeTools.bepaalKwartaal(rekenTijd.beginDatum);
            List<DmfaWerkgeverAangifte> aangiftes = dmfaWerkgeverAangifteService.findByJaarKwartaalStatusNietOnbevestigd(admin, jaar, kwartaal);
            return !aangiftes.isEmpty();
        } else {
            return false;
        }
    }

    private List<RekenHoofd> findBestaandeRekenResultaten(Admin admin, Integer persoonId, RekenTijd rekenTijd, LoonCodeManager loonCodeManager) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.findBestaandeRekenResultaten");

        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.rekenResultatenService.findByPersoonIdBegindatum");
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(rekenTijd.rekenPeriode);
        temporalContext.setWerkTijdstip(rekenTijd.rekenTijdstip);

        List<RekenHoofd> bestaanden = rekenResultatenService.findByPersoonIdBegindatum(admin, persoonId, rekenTijd.beginDatum);

        temporalContext.clearWerkTijdstip();
        temporalContext.clearActualInterval();
        TimeLogContext.getInstance().endTimeLogging();
        for (RekenHoofd hoofd : bestaanden) {
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                AardKodeExtensie looncode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());
                lijn.setAardKodeExtensie(looncode);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return bestaanden;
    }

    private Set<Integer> bepaalTeRekenenOpdrachten(
            Admin admin, List<RekenHoofd> bestaanden, Integer persoonId, Set<Integer> opdrachtNrs,
            RekenTijd rekenTijd, Rekenmodus rekenModus) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.bepaalTeRekenenOpdrachten");
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(rekenTijd.rekenPeriode);
        temporalContext.setWerkTijdstip(rekenTijd.rekenTijdstip);

        List<Opdracht> opdrachten = opdrachtService.findByPersoonOpdrachtNrs(admin, persoonId, opdrachtNrs);
        Set<Integer> opdrachtIds = opdrachten.stream().map(Opdracht::getId).collect(Collectors.toSet());
        Set<Integer> opdrachtIdsNormaal = new HashSet<>();
        Set<Integer> opdrachtIdsVoorschot = new HashSet<>();
        for (RekenHoofd rekenHoofd : bestaanden) {
            if (rekenHoofd.getRekenModus() == Rekenmodus.VOORSCHOT) {
                opdrachtIdsVoorschot.add(rekenHoofd.getOpdracht().getId());
            } else {
                opdrachtIdsNormaal.add(rekenHoofd.getOpdracht().getId());
            }
        }
        opdrachtIdsVoorschot.removeAll(opdrachtIdsNormaal);
        if (rekenModus == Rekenmodus.VOORSCHOT) {
            opdrachtIds.addAll(opdrachtIdsVoorschot);
        } else {
            opdrachtIds.addAll(opdrachtIdsNormaal);
        }

        temporalContext.clearWerkTijdstip();
        temporalContext.clearActualInterval();
        TimeLogContext.getInstance().endTimeLogging();
        return opdrachtIds;
    }

    // Deze is nodig zowel bij vakbondspremie als vrijwiliige brandweer
    private void opvullenKwartaalResultaten(Admin admin, RekenTijd rekenTijd, PersoonsDataManagerImp dataManager, LoonCodeManager loonCodeManager) {
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        boolean isPremieMonth = rekenTijd.getRekenMonthOfYear() == Vakbondspremie.PREMIE_MONTH;
        Persoon persoonKwartaalSimpel = dataManager.getPersoonKwartaalSimpel();
        if (isPremieMonth || RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel)) {
            List<RekenHoofd> kwartaalResultaten = getKwartaalResultaten(admin, persoon, rekenTijd, loonCodeManager, dataManager);
            dataManager.addKwartaalRekenResultaten(kwartaalResultaten);
        }
    }

    private void bepaalOnthaaloudersWerkbonus(Admin admin, Integer persoonId, RekenTijd rekenTijd, PersoonsDataManagerImp dataManager) {
        List<OnthaalOudersWerkbonus> onthaalOudersWerkbonussen =
                onthaalOudersWerkbonusService.findByPersoonIdPeriode(admin, persoonId, rekenTijd.rekenPeriode);
        for (OnthaalOudersWerkbonus werkbonus : onthaalOudersWerkbonussen) {
            dataManager.addOnthaalOudersWerkbonus(werkbonus.getOpdrachtNummer(), werkbonus.getVerminderingLageLonen());
            dataManager.addOnthaalOudersPatronaleVermindering(werkbonus.getOpdrachtNummer(), werkbonus.getVerminderingOnthaalouders());
        }
    }

    private void bepaalPersoonOpdrachtData(
            Admin admin, int persoonId, Set<Integer> teRekenenOpdrachtIds, RekenTijd rekenTijd,
            PersoonsDataManagerImp dataManager, RegulManager regulManager) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.bepaalPersoonOpdrachtData");
        dataManager.setTeRekenenOpdrachtIds(teRekenenOpdrachtIds);

        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.einddatums");
        List<OpdrachtEindDatums> opdrachtEindDatums = opdrachtService.bepaalOpdrachtEindDatums(admin, teRekenenOpdrachtIds, rekenTijd.rekenTijdstip);
        TimeLogContext.getInstance().endTimeLogging();

        List<LocalDateInterval> selectiePeriodes = bepaalSelectiePeriodesVoorPersoonOpdrachtData(rekenTijd, opdrachtEindDatums, dataManager);

        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setWerkTijdstip(rekenTijd.rekenTijdstip);
        for (LocalDateInterval selectiePeriode : selectiePeriodes) {
            getPersoonOpSelectieDatum(admin, persoonId, selectiePeriode, dataManager, rekenTijd, regulManager);
        }
        bepaalPersoonKwartaalSimpel(admin, persoonId, dataManager, rekenTijd);
        getPrestaties(admin, dataManager, rekenTijd);
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenTijd);
        if (tijdperk == AkeTijdperk.DMFAPPL) {
            boolean persoonHeeftOpzeg = bepaalPersoonIsInOpzegOpEerstDagKwartaal(dataManager, rekenTijd);
            if (persoonHeeftOpzeg) {
                LocalDate selectieVorigKwartaal = TimeTools.bepaalSelectieDatumVorigKwartaalDmfappl(rekenTijd);
                getPersoonOpSelectieDatum(admin, persoonId, new Day(selectieVorigKwartaal), dataManager, rekenTijd, regulManager);
            }
        }

        extraSelectieDatumWerkbonusGepensioneerd(admin, persoonId, dataManager, rekenTijd, regulManager);

        dataUitInvoerModule.bepaal(admin, rekenTijd, dataManager, regulManager);
        temporalContext.clearWerkTijdstip();
        TimeLogContext.getInstance().endTimeLogging();
    }

    private void extraSelectieDatumWerkbonusGepensioneerd(
            Admin admin, int persoonId, PersoonsDataManagerImp dataManager, RekenTijd rekenTijd, RegulManager regulManager) {
        if (WerkbonusGepensioneerdActief.isActief(rekenTijd)) {
            Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
            boolean extraSelectieDatum = persoon.getOpdrachten()
                    .stream()
                    .map(Opdracht::getOpperSlices)
                    .flatMap(Collection::stream)
                    .anyMatch(this::testExtraSelectieDatumWerkbonusGepensioneerd);
            if (extraSelectieDatum) {
                getPersoonOpSelectieDatum(admin, persoonId, new Month(WerkbonusGepensioneerdActief.getStartDatum()), dataManager, rekenTijd, regulManager);
            }
        }
    }

    private boolean testExtraSelectieDatumWerkbonusGepensioneerd(Opper opper) {
        boolean startVoor = !opper.getOpdracht().getBeginDatum().isAfter(WerkbonusGepensioneerdActief.getStartDatum());
        boolean notieGepensioneerd = opper.getRszppo().getNotieGepensioneerd() == DmfapplNotieGepens.GEPENSION;
        return startVoor && notieGepensioneerd;
    }

    private List<LocalDateInterval> bepaalSelectiePeriodesVoorPersoonOpdrachtData(
            RekenTijd rekenTijd, List<OpdrachtEindDatums> opdrachtEindDatums, PersoonsDataManagerImp dataManager) {
        List<LocalDateInterval> selectiePeriodes = new ArrayList<>();
        selectiePeriodes.add(new Day(rekenTijd.rekenDatum));
        selectiePeriodes.add(rekenTijd.rekenPeriode);
        for (OpdrachtEindDatums opdrachtEindDatum : opdrachtEindDatums) {
            Opdracht opdracht = opdrachtEindDatum.getOpdracht();
            LocalDate eindDatum = opdrachtEindDatum.getEindDatum();
            dataManager.addOpdrachtEindDatum(opdracht, eindDatum);
            if (eindDatum.isBefore(rekenTijd.rekenDatum)) {
                selectiePeriodes.add(new Day(eindDatum));
            }
        }
        return selectiePeriodes;
    }

    private boolean bepaalPersoonIsInOpzegOpEerstDagKwartaal(PersoonsDataManagerImp dataManager, RekenTijd rekenTijd) {
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        boolean persoonHeeftOpzeg = false;
        firstLoop:
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            for (Opper opper : opdracht.getOpperSlices()) {
                LocalDateInterval interval = rekenTijd.rekenPeriode.overlap(opper.getActualInterval());
                if (isEersteDagKwartaal(interval.getStart()) && opper.getRszppo().getDienstverband() == Dienstverband.NEE_VERBREEK
                        && !opdracht.getBeginDatum().equals(opdracht.getEindDatum())) {
                    persoonHeeftOpzeg = true;
                    dataManager.setOpdrachtInOpzegOpEerstDagKwartaal(opdracht);
                    continue firstLoop;
                }
            }
        }
        return persoonHeeftOpzeg;
    }

    private boolean isEersteDagKwartaal(LocalDate datum) {
        return datum.getDayOfMonth() == 1 && (datum.getMonthOfYear() - 1) % 3 == 0;
    }

