    private List<RekenHoofd> getKwartaalResultaten(
            Admin admin, Persoon persoon, RekenTijd rekenTijd, LoonCodeManager loonCodeManager,
            PersoonsDataManager dataManager) {
        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.getKwartaalResultaten");
        LocalDate huidigBegin = rekenTijd.beginDatum;
        int huidigMaandNr = rekenTijd.beginDatum.getMonthOfYear();
        int startMaandNr = huidigMaandNr - ((huidigMaandNr - 1) % 3);

        Map<Integer, Opdracht> idToOpdrachtMap = AlgemeenTools.maakIdToIdentifiableMap(dataManager.getOpdrachtenOpDatum(rekenTijd.eindDatum, true));
        Set<LocalDate> beginDatums = new HashSet<>();
        for (int i = 0; i < 3; i++) {
            if (startMaandNr + i != huidigMaandNr) {
                LocalDate beginDatum = huidigBegin.withMonthOfYear(startMaandNr + i);
                beginDatums.add(beginDatum);
            }
        }
        TimeLogContext.getInstance().startTimeLogging("RekenMotorService.rekenResultatenService.findByPersoonBegindatum");
        List<RekenHoofd> resultaten = rekenResultatenService.findByPersoonBegindatums(admin, persoon, beginDatums, KWARTAAL_RESULTATEN_FETCH_STRING);
        TimeLogContext.getInstance().endTimeLogging();
        for (RekenHoofd hoofd : resultaten) {
            Integer opdrachtId = hoofd.getOpdracht().getId();
            Opdracht opdracht = idToOpdrachtMap.get(opdrachtId);
            if (opdracht == null) {
                TemporalContext.getInstance().setActualInterval(new Eternity());
                opdracht = opdrachtService.getById(admin, opdrachtId);
                TemporalContext.getInstance().clearActualInterval();
                idToOpdrachtMap.put(opdrachtId, opdracht);
            }

            hoofd.setOpdracht(opdracht);
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                AardKodeExtensie loonCode = loonCodeManager.getById(lijn.getAardKodeExtensie().getId());
                lijn.setAardKodeExtensie(loonCode);
            }
        }
        List<RekenHoofd> kwartaalResultaten = new ArrayList<>(resultaten);
        TimeLogContext.getInstance().endTimeLogging();
        return kwartaalResultaten;
    }

    private void getPersoonOpSelectieDatum(
            Admin admin, int persoonId, LocalDateInterval selectiePeriode, PersoonsDataManagerImp dataManager,
            RekenTijd rekenTijd, RegulManager regulManager) {
        LocalDateInterval interval = new Month(selectiePeriode.getEnd());
        if (dataManager.getPersoonOpDatum(interval.getEnd()) == null) {
            TemporalContext temporalContext = TemporalContext.getInstance();
            temporalContext.setActualInterval(interval);
            Persoon persoon = getPersoonOpSelectieDatum(admin, persoonId);
            List<Opdracht> opdrachten = findOpdrachtenOpSelectieDatum(admin, persoon, interval);

            persoon.setOpdrachten(new HashSet<>(opdrachten));
            for (Opdracht opdracht : opdrachten) {
                entityManager.detach(opdracht);
                opdracht.setPersoon(persoon);
                TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.oppers");
                Opdracht oppers = opperService.getById(admin, opdracht.getId(), OPPER_FETCH_STRING);
                entityManager.detach(oppers);
                TimeLogContext.getInstance().endTimeLogging();
                opdracht.setOpperSlices(oppers.getOpperSlices());
                for (Opper opper : opdracht.getOpperSlices()) {
                    opper.setOpdracht(opdracht);
                    dataManager.addOpperToPersoonsData(opper);
                    checkRegulTool.checkRegulOpper(rekenTijd, opper, regulManager);
                }
                LocalDateInterval inDienstPeriode = dataManager.getInDienstPeriode(opdracht);
                if (inDienstPeriode == null) {
                    inDienstPeriode = extraSqlService.bepaalIndienstPeriode(admin, opdracht.getId());
                    dataManager.addInDienstPeriode(opdracht, inDienstPeriode);
                }

                bepaalSimpelWeddebepaling(admin, opdracht, rekenTijd, interval, dataManager);

            }

            dataManager.addPersoonOpDatum(persoon, interval.getEnd());

            temporalContext.clearActualInterval();
        }
    }

    private Persoon getPersoonOpSelectieDatum(Admin admin, Integer persoonId) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.persoon");
        Persoon persoon = persoonService.getById(admin, persoonId, PERSOON_FETCH_STRING);
        entityManager.detach(persoon);
        TimeLogContext.getInstance().endTimeLogging();
        return persoon;
    }

    private List<Opdracht> findOpdrachtenOpSelectieDatum(Admin admin, Persoon persoon, LocalDateInterval interval) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("persoon.id", Criterium.EQ(persoon.getId()));
        cb.and("opdrachtSlices.beginDatum", Criterium.LE(interval.getEnd()));
        cb.and("opdrachtSlices.eindDatum", Criterium.GE(interval.getStart()));
        cb.fetch(OPDRACHT_FETCH_STRING);
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.opdrachten");
        List<Opdracht> opdrachten = opdrachtService.findByCriteria(admin, cb);
        TimeLogContext.getInstance().endTimeLogging();
        return opdrachten;
    }

    private void bepaalSimpelWeddebepaling(Admin admin, Opdracht opdracht, RekenTijd rekenTijd, LocalDateInterval interval, PersoonsDataManagerImp dataManager) {
        Opper laatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
        if (laatsteGegevens != null) {
            SimpelWeddebepaling simpelWeddebepaling = extraSqlService.getSimpelWeddebepaling(admin, opdracht.getId(), laatsteGegevens.getActualTo());
            dataManager.addSimpelWeddebepalingOpDatum(opdracht, interval.getEnd(), simpelWeddebepaling);
        }
        boolean bonusPens2Ancienniteit =
                constantService.getByCodeDatum(admin, Konstanten.KST_BIJDRAGE_PENS2B_ANCIENNITEIT, rekenTijd.beginDatum).getBoolean();
        if (bonusPens2Ancienniteit) {
            LocalDate zoekDatum;
            if (opdracht.getEindDatum().isBefore(rekenTijd.beginDatum)) {
                zoekDatum = opdracht.getEindDatum();
            } else if (opdracht.getBeginDatum().isAfter(rekenTijd.beginDatum)) {
                zoekDatum = opdracht.getBeginDatum();
            } else {
                zoekDatum = rekenTijd.beginDatum;
            }
            SimpelWeddebepaling simpelWeddebepaling2 = extraSqlService.getSimpelWeddebepaling(admin, opdracht.getId(), zoekDatum);
            dataManager.addSimpelWeddebepalingOpDatum(opdracht, rekenTijd.beginDatum, simpelWeddebepaling2);
        }
    }

    private void bepaalPersoonKwartaalSimpel(Admin admin, int persoonId, PersoonsDataManagerImp dataManager, RekenTijd rekenTijd) {
        Quarter interval = new Quarter(rekenTijd.eindDatum);
        TemporalContext temporalContext = TemporalContext.getInstance();
        temporalContext.setActualInterval(interval);
        Persoon persoon = getPersoonOpSelectieDatum(admin, persoonId);
        List<Opdracht> opdrachten = findOpdrachtenOpSelectieDatum(admin, persoon, interval);

        persoon.setOpdrachten(new HashSet<>(opdrachten));
        for (Opdracht opdracht : opdrachten) {
            entityManager.detach(opdracht);
            opdracht.setPersoon(persoon);
        }

        if (RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(opdrachten)) {
            for (Opdracht opdracht : opdrachten) {
                TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.oppers");
                Opdracht oppers = opperService.getById(admin, opdracht.getId(), OPPER_FETCH_STRING);
                entityManager.detach(oppers);
                TimeLogContext.getInstance().endTimeLogging();
                opdracht.setOpperSlices(oppers.getOpperSlices());
            }
        }

        dataManager.setPersoonKwartaalSimpel(persoon);

        temporalContext.clearActualInterval();

    }

    private void getPrestaties(Admin admin, PersoonsDataManagerImp dataManager, RekenTijd rekenTijd) {
        TimeLogContext.getInstance().startTimeLogging("PersoonsDataManagerFactoryImp.getPersoonPrestatiesOpDatum");
        LocalDateInterval interval = new Month(rekenTijd.eindDatum);
        Persoon persoon = dataManager.getPersoonOpDatum(interval.getEnd());
        if (persoon != null) {
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                for (Opper opper : opdracht.getOpperSlices()) {
                    LocalDateInterval intersect = interval.overlap(opper.getActualInterval());
                    List<NlpPrestatie> prestaties =
                            nlpPrestatieService.findByOpdrachtPeriodeAndWerkTijdstip(admin, opper.getOpdracht(), intersect, rekenTijd.rekenTijdstip);
                    dataManager.addPrestaties(opper, interval.getEnd(), prestaties);
                }
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
    }

